arguments.command:
cd /tmp/sv-2c8a4f3cae4f4ac987b8effa0e459b18/advanced-multi-complexity && dotnet package list --format json 2>/dev/null | python3 -m json.tool > after-cpm-packages.json && python3 -c "
import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                key = (name, fw['framework'], pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)
all_keys = sorted(set(b) | set(a))

changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        changes.append((k[0], k[1], k[2], bv or 'N/A', av or 'N/A'))
    else:
        unchanged.append((k[0], k[1], k[2], bv))

print('=== CHANGES ===')
if changes:
    for c in changes: print(f'{c[0]} | {c[1]} | {c[2]} | {c[3]} -> {c[4]}')
else:
    print('None')
print()
print(f'=== UNCHANGED: {len(unchanged)} packages ===')"

